import React from 'react';

function GameCard({ title, genre }) {
  return (
    <article className="game-card">
      <h2>{title}</h2>
      <p>{genre}</p>
    </article>
  );
}

export default function Games() {
  const games = [
    { id: 1, title: 'Mystic Quest', genre: 'Adventure' },
    { id: 2, title: 'Space Racer', genre: 'Racing' },
  ];

  return (
    <main>
      <h1>Browse Our Selection</h1>
      <section>
        {games.map(g => (
          <GameCard key={g.id} title={g.title} genre={g.genre} />
        ))}
      </section>
    </main>
  );
}
